#include "biblia.h"

void Biblia::CarregarLamentacoes(Biblia* b) {
    b->dados[LAMENTACOES].nome = _("Lamentações");

    b->dados[LAMENTACOES].capitulos[1].versos[1] = _("Como está sentada solitária a cidade que era tão populosa! tornou-se como viúva a que era grande entre as nações! A que era princesa entre as províncias tornou-se avassalada!");
    b->dados[LAMENTACOES].capitulos[1].versos[2] = _("Chora amargamente de noite, e as lágrimas lhe correm pelas faces; não tem quem a console entre todos os seus amantes; todos os seus amigos se houveram aleivosamente com ela; tornaram-se seus inimigos.");
    b->dados[LAMENTACOES].capitulos[1].versos[3] = _("Judá foi para o cativeiro para sofrer aflição e dura servidão; ela habita entre as nações, não acha descanso; todos os seus perseguidores a alcançaram nas suas angústias.");
    b->dados[LAMENTACOES].capitulos[1].versos[4] = _("Os caminhos de Sião pranteiam, porque não há quem venha à assembléia solene; todas as suas portas estão desoladas; os seus sacerdotes suspiram; as suas virgens estão tristes, e ela mesma sofre amargamente.");
    b->dados[LAMENTACOES].capitulos[1].versos[5] = _("Os seus adversários a dominam, os seus inimigos prosperam; porque o Senhor a afligiu por causa da multidão das suas transgressões; os seus filhinhos marcharam para o cativeiro adiante do adversário.");
    b->dados[LAMENTACOES].capitulos[1].versos[6] = _("E da filha de Sião já se foi todo o seu esplendor; os seus príncipes ficaram sendo como cervos que não acham pasto e caminham sem força adiante do perseguidor.");
    b->dados[LAMENTACOES].capitulos[1].versos[7] = _("Lembra-se Jerusalém, nos dias da sua aflição e dos seus exílios, de todas as suas preciosas coisas, que tivera desde os tempos antigos; quando caía o seu povo na mão do adversário, e não havia quem a socorresse, os adversários a viram, e zombaram da sua ruína.");
    b->dados[LAMENTACOES].capitulos[1].versos[8] = _("Jerusalém gravemente pecou, por isso se fez imunda; todos os que a honravam a desprezam, porque lhe viram a nudez; ela também suspira e se volta para trás.");
    b->dados[LAMENTACOES].capitulos[1].versos[9] = _("A sua imundícia estava nas suas fraldas; não se lembrava do seu fim; por isso foi espantosamente abatida; não há quem a console; vê, Senhor, a minha aflição; pois o inimigo se tem engrandecido.");
    b->dados[LAMENTACOES].capitulos[1].versos[10] = _("Estendeu o adversário a sua mão a todas as coisas preciosas dela; pois ela viu entrar no seu santuário as nações, acerca das quais ordenaste que não entrassem na tua congregação.");
    b->dados[LAMENTACOES].capitulos[1].versos[11] = _("Todo o seu povo anda gemendo, buscando o pão; deram as suas coisas mais preciosas a troco de mantimento para refazerem as suas forças. Vê, Senhor, e contempla, pois me tornei desprezível.");
    b->dados[LAMENTACOES].capitulos[1].versos[12] = _("Não vos comove isto a todos vós que passais pelo caminho? Atendei e vede se há dor igual a minha dor, que veio sobre mim, com que o Senhor me afligiu, no dia do furor da sua ira.");
    b->dados[LAMENTACOES].capitulos[1].versos[13] = _("Desde o alto enviou fogo que entra nos meus ossos, o qual se assenhoreou deles; estendeu uma rede aos meus pés, fez-me voltar para trás, tornou-me desolada e desfalecida o dia todo.");
    b->dados[LAMENTACOES].capitulos[1].versos[14] = _("O jugo das minhas transgressões foi atado; pela sua mão elas foram entretecidas e postas sobre o meu pescoço; ele abateu a minha força; entregou-me o Senhor nas mãos daqueles a quem eu não posso resistir.");
    b->dados[LAMENTACOES].capitulos[1].versos[15] = _("O Senhor desprezou todos os meus valentes no meio de mim; convocou contra mim uma assembléia para esmagar os meus mancebos; o Senhor pisou como num lagar a virgem filha de Judá.");
    b->dados[LAMENTACOES].capitulos[1].versos[16] = _("Por estas coisas vou chorando; os meus olhos, os meus olhos se desfazem em águas; porque está longe de mim um consolador que pudesse renovar o meu ânimo; os meus filhos estão desolados, porque prevaleceu o inimigo.");
    b->dados[LAMENTACOES].capitulos[1].versos[17] = _("Estende Sião as suas mãos, não há quem a console; ordenou o Senhor acerca de Jacó que fossem inimigos os que estão em redor dele; Jerusalém se tornou entre eles uma coisa imunda.");
    b->dados[LAMENTACOES].capitulos[1].versos[18] = _("Justo é o Senhor, pois me rebelei contra os seus mandamentos; ouvi, rogo-vos, todos os povos, e vede a minha dor; para o cativeiro foram-se as minhas virgens e os meus mancebos.");
    b->dados[LAMENTACOES].capitulos[1].versos[19] = _("Chamei os meus amantes, mas eles me enganaram; os meus sacerdotes e os meus anciãos expiraram na cidade, enquanto buscavam para si mantimento, para refazerem as suas forças.");
    b->dados[LAMENTACOES].capitulos[1].versos[20] = _("Olha, Senhor, porque estou angustiada; turbadas estão as minhas entranhas; o meu coração está transtornado dentro de mim; porque gravemente me rebelei. Na rua me desfilha a espada, em casa é como a morte.");
    b->dados[LAMENTACOES].capitulos[1].versos[21] = _("Ouviram como estou gemendo; mas não há quem me console; todos os meus inimigos souberam do meu mal; alegram-se de que tu o determinaste; mas, em trazendo tu o dia que anunciaste, eles se tornarão semelhantes a mim.");
    b->dados[LAMENTACOES].capitulos[1].versos[22] = _("Venha toda a sua maldade para a tua presença, e faze-lhes como me fizeste a mim por causa de todas as minhas transgressões; pois muitos são os meus gemidos, e desfalecido está o meu coração.");

    b->dados[LAMENTACOES].capitulos[2].versos[1] = _("Como cobriu o Senhor de nuvens na sua ira a filha de Sião! derrubou do céu à terra a glória de Israel, e no dia da sua ira não se lembrou do escabelo de seus pés.");
    b->dados[LAMENTACOES].capitulos[2].versos[2] = _("Devorou o Senhor sem piedade todas as moradas de Jacó; derrubou no seu furor as fortalezas da filha de Judá; abateu-as até a terra. Tratou como profanos o reino e os seus príncipes.");
    b->dados[LAMENTACOES].capitulos[2].versos[3] = _("No furor da sua ira cortou toda a força de Israel; retirou para trás a sua destra de diante do inimigo; e ardeu contra Jacó, como labareda de fogo que tudo consome em redor.");
    b->dados[LAMENTACOES].capitulos[2].versos[4] = _("Armou o seu arco como inimigo, firmou a sua destra como adversário, e matou todo o que era formoso aos olhos; derramou a sua indignação como fogo na tenda da filha de Sião.");
    b->dados[LAMENTACOES].capitulos[2].versos[5] = _("Tornou-se o Senhor como inimigo; devorou a Israel, devorou todos os seus palácios, destruiu as suas fortalezas, e multiplicou na filha de Judá o pranto e a lamentação.");
    b->dados[LAMENTACOES].capitulos[2].versos[6] = _("E arrancou a sua cabana com violência, como se fosse a de uma horta; destruiu o seu lugar de assembléia; o Senhor entregou ao esquecimento em Sião a assembléia solene e o sábado; e na indignação da sua ira rejeitou com desprezo o rei e o sacerdote.");
    b->dados[LAMENTACOES].capitulos[2].versos[7] = _("Desprezou o Senhor o seu altar, detestou o seu santuário; entregou na mão do inimigo os muros dos seus palácios; deram-se gritos na casa do Senhor, como em dia de reunião solene.");
    b->dados[LAMENTACOES].capitulos[2].versos[8] = _("Resolveu o Senhor destruir o muro da filha de Sião; estendeu o cordel, não reteve a sua mão de fazer estragos; fez gemer o antemuro e o muro; eles juntamente se enfraquecem.");
    b->dados[LAMENTACOES].capitulos[2].versos[9] = _("Sepultadas na terra estão as suas portas; ele destruiu e despedaçou os ferrolhos dela; o seu rei e os seus príncipes estão entre as nações; não há lei; também os seus profetas não recebem visão alguma da parte do Senhor.");
    b->dados[LAMENTACOES].capitulos[2].versos[10] = _("Estão sentados no chão os anciãos da filha de Sião, e ficam calados; lançaram pó sobre as suas cabeças; cingiram sacos; as virgens de Jerusalém abaixaram as suas cabeças até o chão.");
    b->dados[LAMENTACOES].capitulos[2].versos[11] = _("Já se consumiram os meus olhos com lágrimas, turbada está a minha alma, o meu coração se derrama de tristeza por causa do quebrantamento da filha do meu povo; porquanto desfalecem os meninos e as crianças de peito pelas ruas da cidade.");
    b->dados[LAMENTACOES].capitulos[2].versos[12] = _("Ao desfalecerem, como feridos, pelas ruas da cidade, ao exalarem as suas almas no regaço de suas mães, perguntam a elas: Onde está o trigo e o vinho?");
    b->dados[LAMENTACOES].capitulos[2].versos[13] = _("Que testemunho te darei, a que te compararei, ó filha de Jerusalém? A quem te assemelharei, para te consolar, ó virgem filha de Sião? pois grande como o mar é a tua ferida; quem te poderá curar?");
    b->dados[LAMENTACOES].capitulos[2].versos[14] = _("Os teus profetas viram para ti visões falsas e insensatas; e não manifestaram a tua iniqüidade, para te desviarem do cativeiro; mas viram para ti profecias vãs e coisas que te levaram ao exílio.");
    b->dados[LAMENTACOES].capitulos[2].versos[15] = _("Todos os que passam pelo caminho batem palmas contra ti; eles assobiam e meneiam a cabeça sobre a filha de Jerusalém, dizendo: E esta a cidade que denominavam a perfeição da formosura, o gozo da terra toda?");
    b->dados[LAMENTACOES].capitulos[2].versos[16] = _("Todos os teus inimigos abrem as suas bocas contra ti, assobiam, e rangem os dentes; dizem: Devoramo-la; certamente este e o dia que esperávamos; achamo-lo, vimo-lo.");
    b->dados[LAMENTACOES].capitulos[2].versos[17] = _("Fez o Senhor o que intentou; cumpriu a sua palavra, que ordenou desde os dias da antigüidade; derrubou, e não se apiedou; fez que o inimigo se alegrasse por tua causa, exaltou o poder dos teus adversários.");
    b->dados[LAMENTACOES].capitulos[2].versos[18] = _("Clama ao Senhor, ó filha de Sião; corram as tuas lágrimas, como um ribeiro, de dia e de noite; não te dês repouso, nem descansem os teus olhos.");
    b->dados[LAMENTACOES].capitulos[2].versos[19] = _("Levanta-te, clama de noite no princípio das vigias; derrama o teu coração como águas diante do Senhor! Levanta a ele as tuas mãos, pela vida de teus filhinhos, que desfalecem de fome à entrada de todas as ruas.");
    b->dados[LAMENTACOES].capitulos[2].versos[20] = _("Vê, ó Senhor, e considera a quem assim tens tratado! Acaso comerão as mulheres o fruto de si mesmas, as crianças que trazem nos braços? ou matar-se-á no santuário do Senhor o sacerdote e o profeta?");
    b->dados[LAMENTACOES].capitulos[2].versos[21] = _("Jazem por terra nas ruas o moço e o velho; as minhas virgens e os meus jovens vieram a cair à espada; tu os mataste no dia da tua ira; trucidaste-os sem misericórdia.");
    b->dados[LAMENTACOES].capitulos[2].versos[22] = _("Convocaste de toda a parte os meus terrores, como no dia de assembléia solene; não houve no dia da ira do Senhor quem escapasse ou ficasse; aqueles que eu trouxe nas mãos e criei, o meu inimigo os consumiu.");

    b->dados[LAMENTACOES].capitulos[3].versos[1] = _("Eu sou o homem que viu a aflição causada pela vara do seu furor.");
    b->dados[LAMENTACOES].capitulos[3].versos[2] = _("Ele me guiou e me fez andar em trevas e não na luz.");
    b->dados[LAMENTACOES].capitulos[3].versos[3] = _("Deveras fez virar e revirar a sua mão contra mim o dia todo.");
    b->dados[LAMENTACOES].capitulos[3].versos[4] = _("Fez envelhecer a minha carne e a minha pele; quebrou-me os ossos.");
    b->dados[LAMENTACOES].capitulos[3].versos[5] = _("Levantou trincheiras contra mim, e me cercou de fel e trabalho.");
    b->dados[LAMENTACOES].capitulos[3].versos[6] = _("Fez-me habitar em lugares tenebrosos, como os que estavam mortos há muito.");
    b->dados[LAMENTACOES].capitulos[3].versos[7] = _("Cercou-me de uma sebe de modo que não posso sair; agravou os meus grilhões.");
    b->dados[LAMENTACOES].capitulos[3].versos[8] = _("Ainda quando grito e clamo por socorro, ele exclui a minha oração.");
    b->dados[LAMENTACOES].capitulos[3].versos[9] = _("Fechou os meus caminhos com pedras lavradas, fez tortuosas as minhas veredas.");
    b->dados[LAMENTACOES].capitulos[3].versos[10] = _("Fez-se-me como urso de emboscada, um leão em esconderijos.");
    b->dados[LAMENTACOES].capitulos[3].versos[11] = _("Desviou os meus caminhos, e fez-me em pedaços; deixou-me desolado.");
    b->dados[LAMENTACOES].capitulos[3].versos[12] = _("Armou o seu arco, e me pôs como alvo à flecha.");
    b->dados[LAMENTACOES].capitulos[3].versos[13] = _("Fez entrar nos meus rins as flechas da sua aljava.");
    b->dados[LAMENTACOES].capitulos[3].versos[14] = _("Fui feito um objeto de escárnio para todo o meu povo, e a sua canção o dia todo.");
    b->dados[LAMENTACOES].capitulos[3].versos[15] = _("Encheu-me de amarguras, fartou-me de absinto.");
    b->dados[LAMENTACOES].capitulos[3].versos[16] = _("Quebrou com pedrinhas de areia os meus dentes, cobriu-me de cinza.");
    b->dados[LAMENTACOES].capitulos[3].versos[17] = _("Alongaste da paz a minha alma; esqueci-me do que seja a felicidade.");
    b->dados[LAMENTACOES].capitulos[3].versos[18] = _("Digo, pois: Já pereceu a minha força, como também a minha esperança no Senhor.");
    b->dados[LAMENTACOES].capitulos[3].versos[19] = _("Lembra-te da minha aflição e amargura, do absinto e do fel.");
    b->dados[LAMENTACOES].capitulos[3].versos[20] = _("Minha alma ainda os conserva na memória, e se abate dentro de mim.");
    b->dados[LAMENTACOES].capitulos[3].versos[21] = _("Torno a trazer isso à mente, portanto tenho esperança.");
    b->dados[LAMENTACOES].capitulos[3].versos[22] = _("A benignidade do Senhor jamais acaba, as suas misericórdias não têm fim;");
    b->dados[LAMENTACOES].capitulos[3].versos[23] = _("renovam-se cada manhã. Grande é a tua fidelidade.");
    b->dados[LAMENTACOES].capitulos[3].versos[24] = _("A minha porção é o Senhor, diz a minha alma; portanto esperarei nele.");
    b->dados[LAMENTACOES].capitulos[3].versos[25] = _("Bom é o Senhor para os que esperam por ele, para a alma que o busca.");
    b->dados[LAMENTACOES].capitulos[3].versos[26] = _("Bom é ter esperança, e aguardar em silêncio a salvação do Senhor.");
    b->dados[LAMENTACOES].capitulos[3].versos[27] = _("Bom é para o homem suportar o jugo na sua mocidade.");
    b->dados[LAMENTACOES].capitulos[3].versos[28] = _("Que se assente ele, sozinho, e fique calado, porquanto Deus o pôs sobre ele.");
    b->dados[LAMENTACOES].capitulos[3].versos[29] = _("Ponha a sua boca no pó; talvez ainda haja esperança.");
    b->dados[LAMENTACOES].capitulos[3].versos[30] = _("Dê a sua face ao que o fere; farte-se de afronta.");
    b->dados[LAMENTACOES].capitulos[3].versos[31] = _("Pois o Senhor não rejeitará para sempre.");
    b->dados[LAMENTACOES].capitulos[3].versos[32] = _("Embora entristeça a alguém, contudo terá compaixão segundo a grandeza da sua misericórdia.");
    b->dados[LAMENTACOES].capitulos[3].versos[33] = _("Porque não aflige nem entristece de bom grado os filhos dos homens.");
    b->dados[LAMENTACOES].capitulos[3].versos[34] = _("Pisar debaixo dos pés a todos os presos da terra,");
    b->dados[LAMENTACOES].capitulos[3].versos[35] = _("perverter o direito do homem perante a face do Altíssimo,");
    b->dados[LAMENTACOES].capitulos[3].versos[36] = _("subverter o homem no seu pleito, não são do agrado do senhor.");
    b->dados[LAMENTACOES].capitulos[3].versos[37] = _("Quem é aquele que manda, e assim acontece, sem que o Senhor o tenha ordenado?");
    b->dados[LAMENTACOES].capitulos[3].versos[38] = _("Não sai da boca do Altíssimo tanto o mal como o bem?");
    b->dados[LAMENTACOES].capitulos[3].versos[39] = _("Por que se queixaria o homem vivente, o varão por causa do castigo dos seus pecados?");
    b->dados[LAMENTACOES].capitulos[3].versos[40] = _("Esquadrinhemos os nossos caminhos, provemo-los, e voltemos para o Senhor.");
    b->dados[LAMENTACOES].capitulos[3].versos[41] = _("Levantemos os nossos corações com as mãos para Deus no céu dizendo;");
    b->dados[LAMENTACOES].capitulos[3].versos[42] = _("Nós transgredimos, e fomos rebeldes, e não perdoaste,");
    b->dados[LAMENTACOES].capitulos[3].versos[43] = _("Cobriste-te de ira, e nos perseguiste; mataste, não te apiedaste.");
    b->dados[LAMENTACOES].capitulos[3].versos[44] = _("Cobriste-te de nuvens, para que não passe a nossa oração.");
    b->dados[LAMENTACOES].capitulos[3].versos[45] = _("Como escória e refugo nos puseste no meio dos povos.");
    b->dados[LAMENTACOES].capitulos[3].versos[46] = _("Todos os nossos inimigos abriram contra nós a sua boca.");
    b->dados[LAMENTACOES].capitulos[3].versos[47] = _("Temor e cova vieram sobre nós, assolação e destruição.");
    b->dados[LAMENTACOES].capitulos[3].versos[48] = _("Torrentes de águas correm dos meus olhos, por causa da destruição da filha do meu povo.");
    b->dados[LAMENTACOES].capitulos[3].versos[49] = _("Os meus olhos derramam lágrimas, e não cessam, sem haver intermissão,");
    b->dados[LAMENTACOES].capitulos[3].versos[50] = _("até que o Senhor atente e veja desde o céu.");
    b->dados[LAMENTACOES].capitulos[3].versos[51] = _("Os meus olhos me afligem, por causa de todas as filhas da minha cidade.");
    b->dados[LAMENTACOES].capitulos[3].versos[52] = _("Como ave me caçaram os que, sem causa, são meus inimigos.");
    b->dados[LAMENTACOES].capitulos[3].versos[53] = _("Atiraram-me vivo na masmorra, e lançaram pedras sobre mim.");
    b->dados[LAMENTACOES].capitulos[3].versos[54] = _("Águas correram sobre a minha cabeça; eu disse: Estou cortado.");
    b->dados[LAMENTACOES].capitulos[3].versos[55] = _("Invoquei o teu nome, Senhor, desde a profundeza da masmorra.");
    b->dados[LAMENTACOES].capitulos[3].versos[56] = _("Ouviste a minha voz; não escondas o teu ouvido ao meu suspiro, ao meu clamor.");
    b->dados[LAMENTACOES].capitulos[3].versos[57] = _("Tu te aproximaste no dia em que te invoquei; disseste: Não temas.");
    b->dados[LAMENTACOES].capitulos[3].versos[58] = _("Pleiteaste, Senhor, a minha causa; remiste a minha vida.");
    b->dados[LAMENTACOES].capitulos[3].versos[59] = _("Viste, Senhor, a injustiça que sofri; julga tu a minha causa.");
    b->dados[LAMENTACOES].capitulos[3].versos[60] = _("Viste toda a sua vingança, todos os seus desígnios contra mim.");
    b->dados[LAMENTACOES].capitulos[3].versos[61] = _("Ouviste as suas afrontas, Senhor, todos os seus desígnios contra mim,");
    b->dados[LAMENTACOES].capitulos[3].versos[62] = _("os lábios e os pensamentos dos que se levantam contra mim o dia todo.");
    b->dados[LAMENTACOES].capitulos[3].versos[63] = _("Observa-os ao assentarem-se e ao levantarem-se; eu sou a sua canção.");
    b->dados[LAMENTACOES].capitulos[3].versos[64] = _("Tu lhes darás a recompensa, Senhor, conforme a obra das suas mãos.");
    b->dados[LAMENTACOES].capitulos[3].versos[65] = _("Tu lhes darás dureza de coração, maldição tua sobre eles.");
    b->dados[LAMENTACOES].capitulos[3].versos[66] = _("Na tua ira os perseguirás, e os destruirás de debaixo dos teus céus, ó Senhor.");

    b->dados[LAMENTACOES].capitulos[4].versos[1] = _("Como se escureceu o ouro! como se mudou o ouro puríssimo! como estão espalhadas as pedras do santuário pelas esquinas de todas as ruas!");
    b->dados[LAMENTACOES].capitulos[4].versos[2] = _("Os preciosos filhos de Sião, comparáveis a ouro puro, como são agora reputados por vasos de barro, obra das mãos de oleiro!");
    b->dados[LAMENTACOES].capitulos[4].versos[3] = _("Até os chacais abaixam o peito, dão de mamar aos seus filhos; mas a filha do meu povo tornou-se cruel como os avestruzes no deserto.");
    b->dados[LAMENTACOES].capitulos[4].versos[4] = _("A língua do que mama fica pegada pela sede ao seu paladar; os meninos pedem pão, e ninguém lho reparte.");
    b->dados[LAMENTACOES].capitulos[4].versos[5] = _("Os que comiam iguarias delicadas desfalecem nas ruas; os que se criavam em escarlata abraçam monturos.");
    b->dados[LAMENTACOES].capitulos[4].versos[6] = _("Pois maior é a iniqüidade da filha do meu povo do que o pecado de Sodoma, a qual foi subvertida como num momento, sem que mão alguma lhe tocasse.");
    b->dados[LAMENTACOES].capitulos[4].versos[7] = _("Os seus nobres eram mais alvos do que a neve, mais brancos do que o leite, eram mais ruivos de corpo do que o coral, e a sua formosura era como a de safira.");
    b->dados[LAMENTACOES].capitulos[4].versos[8] = _("Mas agora escureceu-se o seu parecer mais do que o negrume; eles não são reconhecidos nas ruas; a sua pele se lhes pegou aos ossos; secou-se, tornou-se como um pau. .");
    b->dados[LAMENTACOES].capitulos[4].versos[9] = _("Os mortos à espada eram mais ditosos do que os mortos à fome, pois estes se esgotavam, como traspassados, por falta dos frutos dos campos.");
    b->dados[LAMENTACOES].capitulos[4].versos[10] = _("As mãos das mulheres compassivas cozeram os próprios filhos; estes lhes serviram de alimento na destruição da filha do meu povo.");
    b->dados[LAMENTACOES].capitulos[4].versos[11] = _("Deu o Senhor cumprimento ao seu furor, derramou o ardor da sua ira; e acendeu um fogo em Sião, que consumiu os seus fundamentos.");
    b->dados[LAMENTACOES].capitulos[4].versos[12] = _("Não creram os reis da terra, bem como nenhum dos moradores do mundo, que adversário ou inimigo pudesse entrar pelas portas de Jerusalém.");
    b->dados[LAMENTACOES].capitulos[4].versos[13] = _("Isso foi por causa dos pecados dos seus profetas e das iniqüidades dos seus sacerdotes, que derramaram no meio dela o sangue dos justos.");
    b->dados[LAMENTACOES].capitulos[4].versos[14] = _("Vagueiam como cegos pelas ruas; andam contaminados de sangue, de tal sorte que não se lhes pode tocar nas roupas.");
    b->dados[LAMENTACOES].capitulos[4].versos[15] = _("Desviai-vos! imundo! gritavam-lhes; desviai-vos, desviai-vos, não toqueis! Quando fugiram, e andaram, vagueando, dizia-se entre as nações: Nunca mais morarão aqui.");
    b->dados[LAMENTACOES].capitulos[4].versos[16] = _("A ira do Senhor os espalhou; ele nunca mais tornará a olhar para eles; não respeitaram a pessoa dos sacerdotes, nem se compadeceram dos velhos.");
    b->dados[LAMENTACOES].capitulos[4].versos[17] = _("Os nossos olhos desfaleciam, esperando o nosso vão socorro. em vigiando olhávamos para uma nação, que não podia, livrai.");
    b->dados[LAMENTACOES].capitulos[4].versos[18] = _("Espiaram os nossos passos, de maneira que não podíamos andar pelas nossas ruas; o nosso fim estava perto; estavam contados os nossos dias, porque era chegado o nosso fim.");
    b->dados[LAMENTACOES].capitulos[4].versos[19] = _("Os nossos perseguidores foram mais ligeiros do que as águias do céu; sobre os montes nos perseguiram, no deserto nos armaram ciladas.");
    b->dados[LAMENTACOES].capitulos[4].versos[20] = _("O fôlego da nossa vida, o ungido do Senhor, foi preso nas covas deles, o mesmo de quem dizíamos: Debaixo da sua sombra viveremos entre as nações.");
    b->dados[LAMENTACOES].capitulos[4].versos[21] = _("Regozija-te, e alegra-te, ó filha de Edom, que habitas na terra de Uz; o cálice te passará a ti também; embebedar-te-ás, e te descobrirás.");
    b->dados[LAMENTACOES].capitulos[4].versos[22] = _("Já se cumpriu o castigo da tua iniqüidade, ó filha de Sião; ele nunca mais te levará para o cativeiro; ele visitará a tua iniqüidade, ó filha de Edom; descobrirá os teus pecados.");

    b->dados[LAMENTACOES].capitulos[5].versos[1] = _("Lembra-te, Senhor, do que nos tem sucedido; considera, e olha para o nosso opróbrio.");
    b->dados[LAMENTACOES].capitulos[5].versos[2] = _("A nossa herdade passou a estranhos, e as nossas casas a forasteiros.");
    b->dados[LAMENTACOES].capitulos[5].versos[3] = _("órfãos somos sem pai, nossas mães são como viuvas.");
    b->dados[LAMENTACOES].capitulos[5].versos[4] = _("A nossa água por dinheiro a bebemos, por preço vem a nossa lenha.");
    b->dados[LAMENTACOES].capitulos[5].versos[5] = _("Os nossos perseguidores estão sobre os nossos pescoços; estamos cansados, e não temos descanso.");
    b->dados[LAMENTACOES].capitulos[5].versos[6] = _("Aos egípcios e aos assírios estendemos as mãos, para nos fartarmos de pão.");
    b->dados[LAMENTACOES].capitulos[5].versos[7] = _("Nossos pais pecaram, e já não existem; e nós levamos as suas iniqüidades.");
    b->dados[LAMENTACOES].capitulos[5].versos[8] = _("Escravos dominam sobre nós; ninguém há que nos arranque da sua mão.");
    b->dados[LAMENTACOES].capitulos[5].versos[9] = _("Com perigo de nossas vidas obtemos o nosso pão, por causa da espada do deserto.");
    b->dados[LAMENTACOES].capitulos[5].versos[10] = _("Nossa pele está abraseada como um forno, por causa do ardor da fome.");
    b->dados[LAMENTACOES].capitulos[5].versos[11] = _("Forçaram as mulheres em Sião, as virgens nas cidades de Judá.");
    b->dados[LAMENTACOES].capitulos[5].versos[12] = _("Príncipes foram enforcados pelas mãos deles; as faces dos anciãos não foram respeitadas.");
    b->dados[LAMENTACOES].capitulos[5].versos[13] = _("Mancebos levaram a mó; meninos tropeçaram sob fardos de lenha.");
    b->dados[LAMENTACOES].capitulos[5].versos[14] = _("Os velhos já não se assentam nas portas, os mancebos já não cantam.");
    b->dados[LAMENTACOES].capitulos[5].versos[15] = _("Cessou o gozo de nosso coração; converteu-se em lamentação a nossa dança.");
    b->dados[LAMENTACOES].capitulos[5].versos[16] = _("Caiu a coroa da nossa cabeça; ai de nós. porque pecamos.");
    b->dados[LAMENTACOES].capitulos[5].versos[17] = _("Portanto desmaiou o nosso coração; por isso se escureceram os nossos olhos.");
    b->dados[LAMENTACOES].capitulos[5].versos[18] = _("Pelo monte de Sião, que está assolado, andam os chacais.");
    b->dados[LAMENTACOES].capitulos[5].versos[19] = _("Tu, Senhor, permaneces eternamente; e o teu trono subsiste de geração em geração.");
    b->dados[LAMENTACOES].capitulos[5].versos[20] = _("Por que te esquecerias de nós para sempre, por que nos desampararias por tanto tempo?");
    b->dados[LAMENTACOES].capitulos[5].versos[21] = _("Converte-nos a ti, Senhor, e seremos convertidos; renova os nossos dias como dantes;");
    b->dados[LAMENTACOES].capitulos[5].versos[22] = _("se é que não nos tens de todo rejeitado, se é que não estás sobremaneira irado contra nos.");

}
